//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    List<String> contributors;
    String license;
    String main;
    String homepage;
    Bugs bugs;
    Repository repository;
    Dependencies dependencies;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.contributors,
        required this.license,
        required this.main,
        required this.homepage,
        required this.bugs,
        required this.repository,
        required this.dependencies,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        contributors: List<String>.from(json["contributors"].map((x) => x)),
        license: json["license"],
        main: json["main"],
        homepage: json["homepage"],
        bugs: Bugs.fromJson(json["bugs"]),
        repository: Repository.fromJson(json["repository"]),
        dependencies: Dependencies.fromJson(json["dependencies"]),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "contributors": List<dynamic>.from(contributors.map((x) => x)),
        "license": license,
        "main": main,
        "homepage": homepage,
        "bugs": bugs.toJson(),
        "repository": repository.toJson(),
        "dependencies": dependencies.toJson(),
    };
}

class Bugs {
    String url;

    Bugs({
        required this.url,
    });

    factory Bugs.fromJson(Map<String, dynamic> json) => Bugs(
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "url": url,
    };
}

class Dependencies {
    String iterall;

    Dependencies({
        required this.iterall,
    });

    factory Dependencies.fromJson(Map<String, dynamic> json) => Dependencies(
        iterall: json["iterall"],
    );

    Map<String, dynamic> toJson() => {
        "iterall": iterall,
    };
}

class Repository {
    String type;
    String url;

    Repository({
        required this.type,
        required this.url,
    });

    factory Repository.fromJson(Map<String, dynamic> json) => Repository(
        type: json["type"],
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "type": type,
        "url": url,
    };
}
